//! Processors for synthetic shell nodes (`comp.*`) generated by the shell
//! compiler ([`ravel_core::composition::compile`]).

use ravel_core::composition::compile::{NodeRole, decode_deterministic_node_id};
use ravel_core::eval::{EvalContext, EvalScope, NodeProcessor, PathSegment, ResolvedParams};
use ravel_core::graph::Node;
use ravel_core::network as net;
use ravel_core::types::{FrameBuffer, NodeData, PortRecord};
use std::sync::Arc;

// ===========================================================================
// comp.network — layer network boundary (REQ-LAYER-006/007)
// ===========================================================================

/// Evaluates the owning layer's network under layer-local time and returns
/// the network's `frame` output. Outside the layer's display interval the
/// network is not evaluated and a transparent frame is produced.
pub struct CompNetworkProcessor;

impl CompNetworkProcessor {
    pub fn from_node(_node: &Node) -> Self {
        Self
    }
}

impl NodeProcessor for CompNetworkProcessor {
    fn process(
        &self,
        node: &Node,
        ctx: &EvalContext,
        inputs: &[Option<Arc<dyn NodeData>>],
        _params: &ResolvedParams,
        scope: &mut dyn EvalScope,
    ) -> anyhow::Result<Arc<dyn NodeData>> {
        let (comp_id, layer_id, role) = decode_deterministic_node_id(node.id)
            .ok_or_else(|| anyhow::anyhow!("comp.network: non-deterministic node id"))?;
        anyhow::ensure!(
            role == NodeRole::Network,
            "comp.network: node id role mismatch"
        );

        let document = scope
            .document()
            .ok_or_else(|| anyhow::anyhow!("comp.network: no document set on the evaluator"))?;
        let comp = document
            .get_composition(comp_id)
            .ok_or_else(|| anyhow::anyhow!("comp.network: composition {comp_id:?} missing"))?
            .clone();
        let layer = comp
            .get_layer(layer_id)
            .ok_or_else(|| anyhow::anyhow!("comp.network: layer {layer_id:?} missing"))?;

        let transparent = || -> Arc<dyn NodeData> {
            Arc::new(FrameBuffer::new_zeroed(
                comp.resolution.0,
                comp.resolution.1,
            ))
        };

        // Layer-local frame: comp_frame - start_frame + in_frame
        // (REQ-LAYER-006). Outside [in, out) the network is not evaluated.
        let local_frame = ctx.frame as i64 - layer.start_frame + layer.in_frame as i64;
        if local_frame < layer.in_frame as i64 || local_frame >= layer.out_frame as i64 {
            return Ok(transparent());
        }

        let out_node = net::find_out_node(&layer.network)
            .ok_or_else(|| anyhow::anyhow!("comp.network: layer network has no net.out node"))?;
        let frame_index = net::frame_port_index(out_node)
            .ok_or_else(|| anyhow::anyhow!("comp.network: net.out has no frame port"))?;

        let local = EvalContext {
            frame: local_frame as u64,
            time: local_frame as f64 / comp.frame_rate.as_f64(),
            fps: comp.frame_rate,
            resolution: comp.resolution,
        };

        let mut bindings: Vec<(String, Arc<dyn NodeData>)> = Vec::new();
        if layer.adjustment
            && let Some(source) = inputs.first().and_then(|i| i.clone())
        {
            bindings.push((net::PORT_SOURCE.to_string(), source));
        }

        let value = scope.evaluate_sub(
            PathSegment::Layer(comp_id, layer_id),
            &layer.network,
            out_node.id,
            &local,
            bindings,
        )?;

        // net.out always produces a PortRecord (one entry per input port);
        // extract the `frame` entry.
        value
            .downcast_ref::<PortRecord>()
            .and_then(|record| record.0.get(frame_index).cloned())
            .ok_or_else(|| anyhow::anyhow!("comp.network: net.out did not produce a frame record"))
    }

    fn is_time_dependent(&self) -> bool {
        true
    }
}

// ===========================================================================
// comp.transform / comp.opacity / comp.merge — shell property nodes
// ===========================================================================

/// Applies the layer's built-in transform.
///
/// Pass-through at this milestone (the real 2D affine implementation lands
/// with the GPU transform pipeline); tolerates a missing input so null
/// layers — which keep a Transform node for parenting — evaluate cleanly.
pub struct CompTransformProcessor;

impl CompTransformProcessor {
    pub fn from_node(_node: &Node) -> Self {
        Self
    }
}

impl NodeProcessor for CompTransformProcessor {
    fn process(
        &self,
        _node: &Node,
        ctx: &EvalContext,
        inputs: &[Option<Arc<dyn NodeData>>],
        _params: &ResolvedParams,
        _scope: &mut dyn EvalScope,
    ) -> anyhow::Result<Arc<dyn NodeData>> {
        Ok(inputs
            .first()
            .and_then(|i| i.clone())
            .unwrap_or_else(|| transparent(ctx)))
    }
}

/// Applies the layer's opacity.
///
/// Pass-through at this milestone (the real implementation multiplies the
/// alpha channel by the layer's opacity channel).
pub struct CompOpacityProcessor;

impl CompOpacityProcessor {
    pub fn from_node(_node: &Node) -> Self {
        Self
    }
}

impl NodeProcessor for CompOpacityProcessor {
    fn process(
        &self,
        _node: &Node,
        ctx: &EvalContext,
        inputs: &[Option<Arc<dyn NodeData>>],
        _params: &ResolvedParams,
        _scope: &mut dyn EvalScope,
    ) -> anyhow::Result<Arc<dyn NodeData>> {
        Ok(inputs
            .first()
            .and_then(|i| i.clone())
            .unwrap_or_else(|| transparent(ctx)))
    }
}

/// Blend-mode merge for layer compositing (`comp.merge.*`), including
/// `comp.merge.adjustment`.
///
/// Currently returns the foreground input when connected, else the
/// background; real alpha compositing with blend modes (and opacity-as-
/// strength for adjustment layers) lands with the GPU merge implementation.
pub struct CompMergeProcessor;

impl CompMergeProcessor {
    pub fn from_node(_node: &Node) -> Self {
        Self
    }
}

impl NodeProcessor for CompMergeProcessor {
    fn process(
        &self,
        node: &Node,
        ctx: &EvalContext,
        inputs: &[Option<Arc<dyn NodeData>>],
        _params: &ResolvedParams,
        scope: &mut dyn EvalScope,
    ) -> anyhow::Result<Arc<dyn NodeData>> {
        // inputs[0] = background, inputs[1] = foreground
        // Outside an adjustment layer's display interval the boundary
        // produces a transparent foreground; bypass the adjustment instead
        // of blanking the composite (REQ-LAYER-010).
        if node.type_key == "comp.merge.adjustment" && adjustment_is_inactive(node, ctx, scope) {
            return Ok(inputs
                .first()
                .and_then(|i| i.clone())
                .unwrap_or_else(|| transparent(ctx)));
        }
        if let Some(fg) = inputs.get(1).and_then(|i| i.clone()) {
            return Ok(fg);
        }
        Ok(inputs
            .first()
            .and_then(|i| i.clone())
            .unwrap_or_else(|| transparent(ctx)))
    }
}

// ===========================================================================
// Helpers
// ===========================================================================

/// Whether the adjustment layer owning this merge node is outside its
/// display interval at `ctx.frame` (and therefore must be bypassed).
fn adjustment_is_inactive(node: &Node, ctx: &EvalContext, scope: &mut dyn EvalScope) -> bool {
    let Some((comp_id, layer_id, _)) = decode_deterministic_node_id(node.id) else {
        return false;
    };
    let Some(document) = scope.document() else {
        return false;
    };
    let Some(layer) = document
        .get_composition(comp_id)
        .and_then(|comp| comp.get_layer(layer_id))
    else {
        return false;
    };
    let local_frame = ctx.frame as i64 - layer.start_frame + layer.in_frame as i64;
    local_frame < layer.in_frame as i64 || local_frame >= layer.out_frame as i64
}

fn transparent(ctx: &EvalContext) -> Arc<dyn NodeData> {
    Arc::new(FrameBuffer::new_zeroed(ctx.resolution.0, ctx.resolution.1))
}
